import React, { useState, useEffect } from 'react';
import Logo from './Logo.png'; 

// BRAND COLORS
const gold = '#D4AF37'; 
const terracotta = '#C04000'; 
const clayLight = '#E2725B'; 
const softCream = '#FDF5E6'; 

function App() {
  // 1. STATE MANAGEMENT
  const [activeCategory, setActiveCategory] = useState('Small Chops');
  const [currentSlide, setCurrentSlide] = useState(0);
  const [cart, setCart] = useState([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [showBankDetails, setShowBankDetails] = useState(false);
  const [isClockedIn, setIsClockedIn] = useState(false);

  // 2. CONTACT & BANK DATA
  const whatsappNumber = "2349122731172";
  const bankInfo = {
    bank: "PREMIUMTRUST BANK",
    account: "0112326977",
    name: "OLUKOYA OMOTOYOSI"
  };

  // 3. PRODUCT DATA
  const slides = [
    { title: "SMALL CHOPS", subtitle: "Lagos' finest selection." },
    { title: "THE HAIR EDIT", subtitle: "Luxury units & blends." },
    { title: "OFFICE LUNCH", subtitle: "Premium corporate dining." }
  ];

  const menuData = {
    CHOPS: [
      { id: 1, name: "The Starter Pack", price: "15,000", desc: "7 Samosas, 7 Springrolls, 15 Puff-puff, 10 Mosa, 4 Grilled Chicken.", img: "/images/starter.jpg" },
      { id: 2, name: "The Signature Platter", price: "25,000", desc: "10 Samosas, 10 Springrolls, 25 Puff-puff, 20 Mosa, 8 Grilled Chicken.", img: "/images/signature.jpg" },
      { id: 3, name: "The Owambe Special", price: "150,000", desc: "Full event catering for 50 people. The ultimate selection.", img: "/images/owambe.jpg" },
      { id: 4, name: "The Customized Package", price: "200,000", desc: "Bespoke menu for 60 people and above. Tailored to your event.", img: "/images/customized.jpg" }
    ],
    LUNCH: [
      { day: "Monday", meal: "Smoky Jollof, Grilled Chicken & Salad" },
      { day: "Tuesday", meal: "Creamy Pasta, Sauteed Prawns & Garlic Bread" },
      { day: "Wednesday", meal: "Native Rice, Shredded Beef & Fried Plantain" },
      { day: "Thursday", meal: "Stir-fry Noodles, Teriyaki Wings & Veggies" },
      { day: "Friday", meal: "Chef's Special Surprise (TGIF Menu)" }
    ],
    WIGS: [
      { type: "Human Hair", items: [
          { id: 201, name: "Raw Cambodian", price: "85,000", desc: "14\" Frontal Unit", img: "/images/hair1.jpg" },
          { id: 202, name: "Bone Straight", price: "120,000", desc: "12\" Double Drawn", img: "/images/hair2.jpg" }
      ]},
      { type: "Premium Fibre", items: [
          { id: 203, name: "Sleek Straight", price: "35,000", desc: "Heat Resistant", img: "/images/hair3.jpg" },
          { id: 204, name: "Deep Wave", price: "38,000", desc: "Pre-styled", img: "/images/hair4.jpg" }
      ]},
      { type: "Hair Blend", items: [
          { id: 205, name: "Piano Wavy", price: "25,000", desc: "24\" T-Closure", img: "/images/hair5.jpg" }
      ]}
    ]
  };

  // 4. LOGIC
  useEffect(() => {
    const timer = setInterval(() => setCurrentSlide((s) => (s + 1) % slides.length), 5000);
    return () => clearInterval(timer);
  }, [slides.length]);

  const addToCart = (item) => {
    setCart([...cart, item]);
  };

  const removeFromCart = (index) => {
    const newCart = [...cart];
    newCart.splice(index, 1);
    setCart(newCart);
  };

  const total = cart.reduce((acc, item) => acc + parseInt(item.price.replace(/,/g, '')), 0);

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', color: '#fff', fontFamily: 'system-ui, sans-serif', WebkitFontSmoothing: 'antialiased' }}>
      
      {/* 1. STICKY PREMIUM HEADER */}
      <header style={{ padding: '15px 20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', position: 'sticky', top: 0, backgroundColor: 'rgba(0,0,0,0.9)', backdropFilter: 'blur(15px)', zIndex: 1000, borderBottom: '1px solid #222' }}>
        <img src={Logo} alt="Logo" style={{ height: '65px', width: 'auto', objectFit: 'contain' }} />
        <div style={{ display: 'flex', gap: '22px', fontSize: '1.5rem', color: softCream }}>
          <span style={{ cursor: 'pointer' }} onClick={() => setActiveCategory('About')}>👤</span>
          <span style={{ position: 'relative', cursor: 'pointer' }} onClick={() => setIsCartOpen(true)}>🛒
            <span style={{ position: 'absolute', top: '-8px', right: '-12px', background: terracotta, color: '#fff', borderRadius: '50%', padding: '4px 7px', fontSize: '0.8rem', fontWeight: 'bold' }}>{cart.length}</span>
          </span>
        </div>
      </header>

      {/* 2. ENLARGED HERO BANNER */}
      <div style={{ width: '100%', height: '180px', position: 'relative', overflow: 'hidden', background: `linear-gradient(145deg, ${terracotta} 0%, ${clayLight} 100%)` }}>
        {slides.map((slide, index) => (
          <div key={index} style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', opacity: index === currentSlide ? 1 : 0, transition: 'opacity 1.5s ease-in-out', display: 'flex', flexDirection: 'column', justifyContent: 'center', padding: '0 30px' }}>
            <h2 style={{ fontSize: '1.8rem', color: '#fff', fontWeight: '900', margin: 0, letterSpacing: '1px', textTransform: 'uppercase' }}>{slide.title}</h2>
            <p style={{ fontSize: '1.1rem', color: softCream, margin: '8px 0 0', opacity: 0.9 }}>{slide.subtitle}</p>
          </div>
        ))}
      </div>

      {/* 3. BUSINESS BRANDING */}
      <div style={{ padding: '25px 30px 10px' }}>
        <h1 style={{ fontSize: '1.6rem', margin: '0', color: '#fff', fontWeight: '800' }}>Àmí by T</h1>
        <p style={{ fontSize: '1rem', color: '#888', margin: '6px 0 20px' }}>● Opened · Closes 08:00 PM · Ikeja, Lagos</p>
        <div style={{ display: 'flex', gap: '15px' }}>
          <button style={{ flex: 1, padding: '14px', borderRadius: '12px', border: 'none', backgroundColor: softCream, color: '#000', fontWeight: 'bold', fontSize: '1rem' }}>Pickup</button>
          <button style={{ flex: 1, padding: '14px', borderRadius: '12px', border: `2px solid ${terracotta}`, backgroundColor: 'transparent', color: '#fff', fontSize: '1rem', fontWeight: 'bold' }}>Delivery</button>
        </div>
      </div>

      {/* 4. LARGE CATEGORY NAV */}
      <div style={{ display: 'flex', gap: '12px', overflowX: 'auto', padding: '20px 30px', scrollbarWidth: 'none' }}>
        {['Small Chops', 'Office Lunch', 'Wigs', 'About'].map((item) => (
          <button key={item} onClick={() => {setActiveCategory(item); setShowBankDetails(false);}} style={{ whiteSpace: 'nowrap', padding: '12px 24px', borderRadius: '25px', border: 'none', backgroundColor: activeCategory === item ? terracotta : '#1a1a1a', color: activeCategory === item ? '#fff' : '#aaa', fontSize: '1rem', fontWeight: '700', transition: 'all 0.3s ease' }}>
            {item}
          </button>
        ))}
      </div>

      {/* 5. MAIN CONTENT AREA */}
      <main style={{ paddingBottom: '140px' }}>
        
        {/* SMALL CHOPS SECTION (Enlarged visuals and text) */}
        {activeCategory === 'Small Chops' && menuData.CHOPS.map((item) => (
          <div key={item.id} style={{ display: 'flex', backgroundColor: '#111', borderRadius: '16px', margin: '0 25px 18px', padding: '18px', alignItems: 'center', border: '1px solid #222' }}>
            <div style={{ width: '110px', height: '110px', backgroundColor: '#000', borderRadius: '12px', marginRight: '18px', overflow: 'hidden', flexShrink: 0 }}>
              <img src={item.img} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} onError={(e) => e.target.style.display='none'} />
            </div>
            <div style={{ flex: 1 }}>
              <h4 style={{ fontSize: '1.1rem', margin: '0', color: '#fff', fontWeight: '700' }}>{item.name}</h4>
              <p style={{ fontSize: '0.9rem', color: '#888', margin: '6px 0', lineHeight: '1.4' }}>{item.desc}</p>
              <div style={{ fontSize: '1.2rem', fontWeight: 'bold', color: gold, marginTop: '5px' }}>₦{item.price}</div>
            </div>
            <button onClick={() => addToCart(item)} style={{ backgroundColor: terracotta, color: '#fff', border: 'none', borderRadius: '25px', padding: '10px 20px', fontSize: '0.9rem', fontWeight: '900', marginLeft: '10px' }}>ADD</button>
          </div>
        ))}

        {/* OFFICE LUNCH SECTION */}
        {activeCategory === 'Office Lunch' && (
          <div style={{ padding: '0 30px' }}>
            <div style={{ backgroundColor: '#0A0A0A', border: `2px solid ${isClockedIn ? '#2ecc71' : terracotta}`, padding: '40px 25px', borderRadius: '16px', textAlign: 'center', marginBottom: '25px' }}>
              <h4 style={{ color: isClockedIn ? '#2ecc71' : gold, fontSize: '1.4rem', fontWeight: 'bold' }}>{isClockedIn ? "Enjoy Your Meal! ✅" : "Good Morning, Champion. ✨"}</h4>
              <button onClick={() => setIsClockedIn(true)} disabled={isClockedIn} style={{ backgroundColor: isClockedIn ? '#2ecc71' : terracotta, color: '#fff', border: 'none', padding: '16px 35px', borderRadius: '12px', fontWeight: 'bold', fontSize: '1rem', marginTop: '20px' }}>
                {isClockedIn ? "CLOCKED IN" : "CLOCK IN FOR LUNCH"}
              </button>
            </div>
            {menuData.LUNCH.map((item) => (
              <div key={item.day} style={{ padding: '20px 0', borderBottom: '1px solid #222' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <span style={{ color: terracotta, fontWeight: '800', fontSize: '1.1rem' }}>{item.day}</span>
                  <span style={{ color: '#fff', fontSize: '1rem', textAlign: 'right', flex: 1, marginLeft: '20px' }}>{item.meal}</span>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* WIGS SECTION (Enlarged visuals) */}
        {activeCategory === 'Wigs' && menuData.WIGS.map((cat) => (
          <div key={cat.type} style={{ padding: '0 30px', marginBottom: '30px' }}>
            <h3 style={{ fontSize: '0.9rem', color: terracotta, textTransform: 'uppercase', letterSpacing: '2px', marginBottom: '15px', fontWeight: '900' }}>{cat.type}</h3>
            {cat.items.map((item) => (
              <div key={item.id} style={{ display: 'flex', backgroundColor: '#111', borderRadius: '16px', marginBottom: '15px', padding: '18px', alignItems: 'center', border: '1px solid #222' }}>
                <div style={{ width: '100px', height: '100px', backgroundColor: '#000', borderRadius: '12px', marginRight: '18px', overflow: 'hidden', flexShrink: 0 }}>
                  <img src={item.img} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} onError={(e) => e.target.style.display='none'} />
                </div>
                <div style={{ flex: 1 }}>
                  <h4 style={{ fontSize: '1.1rem', color: '#fff', fontWeight: '700' }}>{item.name}</h4>
                  <p style={{ fontSize: '0.9rem', color: '#888', margin: '4px 0' }}>{item.desc}</p>
                  <div style={{ color: gold, fontSize: '1.2rem', fontWeight: 'bold', marginTop: '5px' }}>₦{item.price}</div>
                </div>
                <button onClick={() => addToCart(item)} style={{ backgroundColor: terracotta, color: '#fff', border: 'none', borderRadius: '25px', padding: '10px 20px', fontSize: '0.9rem', fontWeight: '900' }}>ADD</button>
              </div>
            ))}
          </div>
        ))}
      </main>

      {/* 6. BIGGER FLOATING CHECKOUT BAR */}
      {cart.length > 0 && (
        <div onClick={() => setIsCartOpen(true)} style={{ position: 'fixed', bottom: '25px', left: '50%', transform: 'translateX(-50%)', width: '92%', maxWidth: '500px', backgroundColor: terracotta, padding: '20px', borderRadius: '20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', boxShadow: '0 15px 35px rgba(0,0,0,0.6)', cursor: 'pointer', zIndex: 1001 }}>
          <div style={{ fontWeight: '900', fontSize: '1.1rem' }}>{cart.length} ITEMS</div>
          <div style={{ fontWeight: '900', fontSize: '1.1rem' }}>VIEW CART ₦{total.toLocaleString()}</div>
        </div>
      )}

      {/* 7. CART MODAL */}
      {isCartOpen && (
        <div style={{ position: 'fixed', bottom: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(0,0,0,0.96)', zIndex: 2000, display: 'flex', alignItems: 'flex-end' }}>
          <div style={{ width: '100%', backgroundColor: '#111', borderTopLeftRadius: '35px', borderTopRightRadius: '35px', padding: '40px 30px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '25px' }}>
              <h3 style={{ color: gold, margin: 0, fontSize: '1.6rem' }}>{showBankDetails ? "Payment Details" : "Your Selection"}</h3>
              <button onClick={() => {setIsCartOpen(false); setShowBankDetails(false);}} style={{ background: 'none', border: 'none', color: '#fff', fontSize: '2.2rem' }}>✕</button>
            </div>

            {!showBankDetails ? (
              <>
                <div style={{ maxHeight: '40vh', overflowY: 'auto' }}>
                  {cart.map((item, index) => (
                    <div key={index} style={{ display: 'flex', justifyContent: 'space-between', padding: '18px 0', borderBottom: '1px solid #222' }}>
                      <span style={{ fontSize: '1.1rem', fontWeight: '500' }}>{item.name}</span>
                      <div style={{ textAlign: 'right' }}>
                        <span style={{ color: gold, fontSize: '1.1rem', fontWeight: 'bold' }}>₦{item.price}</span>
                        <br/><button onClick={() => removeFromCart(index)} style={{ background: 'none', border: 'none', color: terracotta, fontSize: '0.9rem', fontWeight: 'bold', marginTop: '5px', padding: 0 }}>Remove</button>
                      </div>
                    </div>
                  ))}
                </div>
                <div style={{ marginTop: '30px' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '30px' }}>
                    <span style={{ fontSize: '1.2rem' }}>Total Amount</span>
                    <span style={{ fontSize: '1.8rem', fontWeight: '900', color: gold }}>₦{total.toLocaleString()}</span>
                  </div>
                  <button onClick={() => setShowBankDetails(true)} style={{ width: '100%', padding: '20px', backgroundColor: gold, color: '#000', border: 'none', borderRadius: '15px', fontWeight: '900', fontSize: '1.1rem', marginBottom: '15px' }}>BANK TRANSFER</button>
                  <button onClick={() => window.open(`https://wa.me/${whatsappNumber}?text=Order: ${cart.map(i => i.name).join(', ')}. Total: ₦${total.toLocaleString()}`)} style={{ width: '100%', padding: '20px', backgroundColor: '#25D366', color: '#fff', border: 'none', borderRadius: '15px', fontWeight: '900', fontSize: '1.1rem' }}>WHATSAPP ORDER</button>
                </div>
              </>
            ) : (
              <div style={{ textAlign: 'center' }}>
                <h2 style={{ color: gold, fontSize: '2rem', marginBottom: '20px' }}>₦{total.toLocaleString()}</h2>
                <div style={{ backgroundColor: '#000', padding: '25px', borderRadius: '18px', textAlign: 'left', border: `1px solid ${gold}44`, lineHeight: '2' }}>
                  <p style={{ fontSize: '1.1rem' }}><strong>Bank:</strong> {bankInfo.bank}</p>
                  <p style={{ fontSize: '1.1rem' }}><strong>Account:</strong> {bankInfo.account}</p>
                  <p style={{ fontSize: '1.1rem' }}><strong>Name:</strong> {bankInfo.name}</p>
                </div>
                <button onClick={() => window.open(`https://wa.me/${whatsappNumber}?text=Payment Receipt for ₦${total.toLocaleString()}`)} style={{ width: '100%', marginTop: '25px', padding: '20px', backgroundColor: '#25D366', color: '#fff', border: 'none', borderRadius: '15px', fontWeight: '900', fontSize: '1.1rem' }}>SEND RECEIPT ON WHATSAPP</button>
                <button onClick={() => setShowBankDetails(false)} style={{ background: 'none', border: 'none', color: '#666', marginTop: '20px', fontSize: '1rem', textDecoration: 'underline' }}>Back</button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
